/* ============================================================
   NFITNESS 360 — Generador del reporte horizontal (HTML)
   Se envía al Apps Script, que lo convierte a PDF y lo sube a
   Drive. Alimentado por los datos reales del plan + menús.
   ============================================================ */

const FONT_CSS = `@font-face{font-family:'Montserrat';font-style:normal;font-weight:400;src:url(data:font/woff2;base64,) format('woff2');}@font-face{font-family:'Montserrat';font-style:normal;font-weight:600;src:url(data:font/woff2;base64,) format('woff2');}@font-face{font-family:'Montserrat';font-style:normal;font-weight:700;src:url(data:font/woff2;base64,) format('woff2');}@font-face{font-family:'Montserrat';font-style:normal;font-weight:800;src:url(data:font/woff2;base64,) format('woff2');}`;
const LOGO = "data:image/png;base64,";

const TAUPE = '#8E837B', TAUPE2 = '#978C87', TAN = '#CDA788', CREAM = '#EEE4DA', INK = '#4A443E', LINE = '#E0D6CB', SOFT = '#6E645C';

const GSHORT = ['Cereales', 'Cereales c/grasa', 'Leguminosas', 'Verdura', 'Fruta', 'P. animal MB', 'P. animal B', 'P. animal M', 'P. animal A', 'Leche desc.', 'Leche semi', 'Leche entera', 'Leche c/az.', 'Grasas', 'Grasas c/prot', 'Azúcares', 'Az. c/grasa', 'Libres'];

